import { useState, useEffect } from "react";

const LOGO_SRC = "data:image/png;base64,";


const C = {
  bg:"#F5F2EB",surface:"#FDFBF7",card:"#FFFFFF",border:"#E2DDD4",
  accent:"#D4651A",accentL:"#FDF0E8",accentD:"#A84E12",
  green:"#2A7D4F",greenL:"#E8F5EE",blue:"#1D6FA4",blueL:"#E8F2FA",
  warn:"#C4900A",warnL:"#FEF7E6",danger:"#C0392B",dangerL:"#FDECEA",
  text:"#1A1612",muted:"#7C756C",soft:"#4A4540",
};

const PHARMACY = {
  name:"Pharmacie Saint-Martin",
  address:"150 place Jean Jaurès, 62110 Hénin-Beaumont",
  lat:50.4192,lng:2.9517,
};

const SLOTS=["08h–09h","10h–11h","12h–13h","13h–14h","15h–16h","17h–18h","18h–19h"];
const POIDS=["léger","lourd","fragile (réfrigéré)"];

function pseudoGeocode(address,id){
  const seed=id.split("").reduce((a,c)=>a+c.charCodeAt(0),0);
  const r=(s,range)=>((s*9301+49297)%233280)/233280*range-range/2;
  return{lat:50.4192+r(seed,0.08),lng:2.9517+r(seed*3,0.14)};
}

function optimizeRoute(selected,pLat,pLng){
  if(!selected.length)return null;
  const dist=(a,b)=>Math.sqrt((a.lat-b.lat)**2+(a.lng-b.lng)**2);
  const rem=[...selected];const route=[];
  let cur={lat:pLat,lng:pLng};
  while(rem.length){
    const n=rem.reduce((b,p)=>dist(cur,p)<dist(cur,b)?p:b,rem[0]);
    route.push(n);rem.splice(rem.indexOf(n),1);cur=n;
  }
  let total=0,prev={lat:pLat,lng:pLng};
  const enriched=route.map((p,i)=>{
    const dx=(p.lat-prev.lat)*111,dy=(p.lng-prev.lng)*74;
    const km=Math.sqrt(dx*dx+dy*dy);total+=km;
    const eta=Math.round(km/0.25);prev=p;
    return{...p,stop:i+1,kmFromPrev:km.toFixed(1),etaFromPrev:eta};
  });
  const dx=(pLat-prev.lat)*111,dy=(pLng-prev.lng)*74;
  total+=Math.sqrt(dx*dx+dy*dy);
  return{route:enriched,totalKm:total.toFixed(1),totalMin:Math.round(total/0.25*1.3)};
}

function buildMapsUrl(pharmacy,route){
  const o=encodeURIComponent(pharmacy.address);
  const wp=route.map(p=>encodeURIComponent(p.address)).join("|");
  return`https://www.google.com/maps/dir/?api=1&origin=${o}&destination=${o}&waypoints=${wp}&travelmode=driving`;
}

const G=`
  @import url('https://fonts.googleapis.com/css2?family=Fraunces:wght@300;600;700&family=Epilogue:wght@300;400;500;600&display=swap');
  *{box-sizing:border-box;margin:0;padding:0;}
  body{background:${C.bg};color:${C.text};font-family:'Epilogue',sans-serif;}
  input,select,textarea{font-family:'Epilogue',sans-serif;font-size:14px;border:1.5px solid ${C.border};border-radius:8px;padding:10px 13px;width:100%;outline:none;background:white;color:${C.text};transition:border .2s;}
  input:focus,select:focus,textarea:focus{border-color:${C.accent};}
  input::placeholder,textarea::placeholder{color:${C.muted};}
  button{cursor:pointer;font-family:'Epilogue',sans-serif;}
  @keyframes fadeUp{from{opacity:0;transform:translateY(10px);}to{opacity:1;transform:translateY(0);}}
  .fadeUp{animation:fadeUp .3s ease forwards;}
  .ch:hover{box-shadow:0 4px 18px rgba(0,0,0,0.09);transform:translateY(-1px);}
  .ch{transition:all .2s;}
  .pr:hover{background:${C.accentL};}
  .pr{transition:background .15s;}
  ::-webkit-scrollbar{width:4px;}
  ::-webkit-scrollbar-thumb{background:${C.border};border-radius:4px;}
`;

const Btn=({children,onClick,variant="primary",size="md",disabled,full,style={}})=>{
  const sz={sm:{padding:"6px 13px",fontSize:12},md:{padding:"10px 20px",fontSize:13},lg:{padding:"13px 26px",fontSize:14}};
  const v={
    primary:{background:C.accent,color:"white",border:"none"},
    secondary:{background:"transparent",color:C.accent,border:`1.5px solid ${C.accent}`},
    ghost:{background:"transparent",color:C.muted,border:`1.5px solid ${C.border}`},
    danger:{background:C.danger,color:"white",border:"none"},
    green:{background:C.green,color:"white",border:"none"},
  };
  return<button disabled={disabled} onClick={disabled?undefined:onClick}
    style={{borderRadius:8,fontWeight:500,transition:"all .2s",display:"inline-flex",alignItems:"center",
      justifyContent:"center",gap:6,opacity:disabled?.45:1,width:full?"100%":undefined,
      ...sz[size],...v[variant],...style}}>{children}</button>;
};

const Field=({label,children,required})=>(
  <div style={{marginBottom:14}}>
    <label style={{display:"block",fontSize:11,color:C.muted,fontWeight:600,letterSpacing:.8,marginBottom:6,textTransform:"uppercase"}}>
      {label}{required&&<span style={{color:C.danger}}> *</span>}
    </label>
    {children}
  </div>
);

const Badge=({children,color=C.accent,bg=C.accentL})=>(
  <span style={{display:"inline-flex",alignItems:"center",gap:4,padding:"3px 9px",borderRadius:12,background:bg,color,fontSize:11,fontWeight:600,whiteSpace:"nowrap"}}>{children}</span>
);

const Modal=({title,onClose,children,width=520})=>(
  <div onClick={onClose} style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.35)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:200,padding:20}}>
    <div onClick={e=>e.stopPropagation()} className="fadeUp"
      style={{background:C.card,borderRadius:14,width:"100%",maxWidth:width,maxHeight:"90vh",overflowY:"auto",boxShadow:"0 20px 60px rgba(0,0,0,0.18)"}}>
      <div style={{padding:"20px 24px",borderBottom:`1px solid ${C.border}`,display:"flex",justifyContent:"space-between",alignItems:"center",position:"sticky",top:0,background:C.card,zIndex:1}}>
        <h3 style={{fontFamily:"'Fraunces',serif",fontSize:18,fontWeight:600}}>{title}</h3>
        <button onClick={onClose} style={{background:"none",border:"none",fontSize:22,color:C.muted,cursor:"pointer",lineHeight:1}}>×</button>
      </div>
      <div style={{padding:"22px 24px"}}>{children}</div>
    </div>
  </div>
);

const EMPTY={nom:"",prenom:"",address:"",phone:"",ordonnance:"",slot:"12h–13h",notes:"",poids:"léger"};

const PatientForm=({initial=EMPTY,onSave,onCancel})=>{
  const[f,setF]=useState({...EMPTY,...initial});
  const upd=k=>e=>setF(p=>({...p,[k]:e.target.value}));
  const ok=f.nom.trim()&&f.prenom.trim()&&f.address.trim()&&f.phone.trim();
  return(
    <div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
        <Field label="Nom" required><input placeholder="Dupont" value={f.nom} onChange={upd("nom")}/></Field>
        <Field label="Prénom" required><input placeholder="Marie" value={f.prenom} onChange={upd("prenom")}/></Field>
      </div>
      <Field label="Adresse complète" required>
        <input placeholder="12 rue Pasteur, 62110 Hénin-Beaumont" value={f.address} onChange={upd("address")}/>
      </Field>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
        <Field label="Téléphone" required><input placeholder="06 12 34 56 78" value={f.phone} onChange={upd("phone")}/></Field>
        <Field label="N° Ordonnance"><input placeholder="ORX-001" value={f.ordonnance} onChange={upd("ordonnance")}/></Field>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
        <Field label="Créneau de livraison">
          <select value={f.slot} onChange={upd("slot")}>{SLOTS.map(s=><option key={s}>{s}</option>)}</select>
        </Field>
        <Field label="Type de colis">
          <select value={f.poids} onChange={upd("poids")}>{POIDS.map(p=><option key={p}>{p}</option>)}</select>
        </Field>
      </div>
      <Field label="Notes / Instructions">
        <textarea rows={3} placeholder="Allergie, étage, appeler avant, réfrigéré..." value={f.notes} onChange={upd("notes")}/>
      </Field>
      <div style={{display:"flex",gap:10,justifyContent:"flex-end",marginTop:6}}>
        <Btn variant="ghost" onClick={onCancel}>Annuler</Btn>
        <Btn disabled={!ok} onClick={()=>onSave(f)}>💾 Enregistrer</Btn>
      </div>
    </div>
  );
};

